function solve(l, r, directions) {
    let goodCount = 0;

    /**
     * Checks if a given number x is a "good" integer.
     * @param {number} x - The integer to check.
     * @param {string} directions - The 6 direction characters.
     * @returns {boolean} True if x is a good integer, false otherwise.
     */
    const isGood = (x, directions) => {
        // 1. Padding: Convert x to 16-digit string, zero-padded.
        const xStr = String(x).padStart(16, '0');

        // 2. Grid Formation (4x4)
        // Initialize 4 rows, each containing 4 zeros.
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));

        for (let k = 0; k < 16; k++) {
            const digit = parseInt(xStr[k]);
            const row = Math.floor(k / 4);
            const col = k % 4;
            grid[row][col] = digit;
        }

        // 3. Path Traversal & Sequence Generation
        let r = 0;
        let c = 0;

        // Sequence starts with the value at (0, 0)
        const sequence = [grid[0][0]];

        // Apply 6 moves defined by directions
        for (let i = 0; i < 6; i++) {
            const move = directions[i];

            // Apply movement
            if (move === 'D') {
                r += 1;
            } else if (move === 'R') {
                c += 1;
            }

            // Since total moves are 3D and 3R, and grid is 4x4 (0..3), 
            // the coordinates (r, c) will remain within bounds [0, 3].

            sequence.push(grid[r][c]);
        }

        // 4. Non-decreasing Check (Sequence length is 7)
        for (let i = 0; i < 6; i++) {
            // Check sequence[i] <= sequence[i+1]
            if (sequence[i] > sequence[i + 1]) {
                return false;
            }
        }

        return true;
    };

    // Iterate from L to R and count good integers
    for (let x = l; x <= r; x++) {
        if (isGood(x, directions)) {
            goodCount++;
        }
    }

    return goodCount;
}

